def get_labeled_dataset() -> List[Dict[str, str]]:
    """Return the full labeled evaluation dataset."""
    return LABELED_DATASET


def get_dataset_stats() -> Dict[str, int]:
    """Return label distribution statistics."""
    counts = {"positive": 0, "negative": 0, "neutral": 0}
    for item in LABELED_DATASET:
        counts[item["label"]] += 1
    return {
        "total": len(LABELED_DATASET),
        **counts,
    }
